// Hàm tách văn bản tại dòng gần nhất sau từ thứ wordLimit
function splitTextAtNewlineAfterWordCount(text, wordLimit) {
  let wordCount = 0;
  let cutIndex = 0;
  let inWord = false;
  let lastWordEnd = 0;

  // Duyệt qua từng ký tự để đếm từ
  for (let i = 0; i < text.length; i++) {
    const isSpace = text[i] === " ";
    const isNewline = text[i] === "\n";

    if (!inWord && !isSpace && !isNewline) {
      // Bắt đầu một từ mới
      inWord = true;
      wordCount++;
    } else if (inWord && (isSpace || isNewline)) {
      // Kết thúc một từ
      inWord = false;
      lastWordEnd = i; // Lưu vị trí kết thúc từ
    }

    // Nếu đã đạt đến từ thứ wordLimit, tìm xuống dòng gần nhất
    if (wordCount >= wordLimit && !inWord) {
      if (isNewline) {
        cutIndex = i + 1; // Cắt ngay sau ký tự xuống dòng
        break;
      }
    }
  }

  // Nếu không tìm thấy xuống dòng hoặc không đủ từ
  if (cutIndex === 0) {
    // Nếu có ít hơn wordLimit từ, trả về toàn bộ chuỗi
    if (wordCount < wordLimit) {
      return { firstPart: text, remainingPart: "" };
    }
    // Nếu không có xuống dòng sau từ thứ wordLimit, cắt tại từ thứ wordLimit
    cutIndex = lastWordEnd;
  }

  // Cắt chuỗi thành hai phần
  const firstPart = text.substring(0, cutIndex);
  const remainingPart = text.substring(cutIndex);

  return { firstPart, remainingPart };
}

// Gọi hàm để tách văn bản tại dòng gần nhất sau từ thứ 480
const result = splitTextAtNewlineAfterWordCount(inputText, 480);

// Trả về kết quả
return [
  {
    json: {
      firstPart: result.firstPart || "",
      remainingPart: result.remainingPart || ""
    }
  }];

