    .replace(/&#x27;/g, "'")
    .replace(/&#039;/g, "'")
    .trim();
};

// Duyệt qua từng item (sẽ là đúng 10 items nếu node trước trả 10)
const cleanedItems = items.map(item => {
  // Clone dữ liệu để không làm thay đổi gốc
  const data = { ...item.json };

  // Làm sạch các field cần thiết
  if (data.name !== undefined) {
    data.name = decodeHtmlEntities(data.name);
  }
  if (data.description !== undefined) {
    data.description = decodeHtmlEntities(data.description);
  }
  // Slug thường không cần decode &amp; → & (vì slug không nên chứa &), nên mình để nguyên
  // Nếu bạn muốn decode slug thì bỏ comment dòng dưới
  // if (data.slug !== undefined) data.slug = decodeHtmlEntities(data.slug);

  // Trả về item đã được làm sạch
  return {
    json: data,
    // Giữ nguyên pairedItem nếu có (đảm bảo liên kết với item gốc)
    pairedItem: item.pairedItem || { item: item.pairedItem?.item }
  };
});

// Quan trọng: Trả về toàn bộ mảng đã xử lý → n8n sẽ nhận đúng 10 items
return cleanedItems;

